module.exports = {
  preset: 'ts-jest',
  testEnvironment: 'node',
  testMatch: ['**/tests/**/*.test.ts'],
  moduleFileExtensions: ['ts', 'js', 'json'],
  verbose: true
};

import express from 'express';
import path from 'path';

const app = express();

app.use(express.json());

// Serve static files from src/public
const publicDir = path.resolve(process.cwd(), 'src', 'public');
app.use(express.static(publicDir));

// Health route for tests and uptime checks
app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

// Root route explicitly serves index.html (also handled by express.static)
app.get('/', (_req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

export default app;

import app from './app';

const PORT = Number(process.env.PORT ?? 4445);

app.listen(PORT, () => {
  // eslint-disable-next-line no-console
  console.log(`Server listening on http://localhost:${PORT}`);
});

import request from 'supertest';
import app from '../src/app';

describe('Express app', () => {
  it('GET /health returns status ok', async () => {
    const res = await request(app).get('/health');
    expect(res.status).toBe(200);
    expect(res.body).toEqual({ status: 'ok' });
  });

  it('GET / serves HTML', async () => {
    const res = await request(app).get('/');
    expect(res.status).toBe(200);
    expect(res.headers['content-type']).toMatch(/html/);
    expect(res.text).toMatch(/Hello World/);
  });
});
